{id:71,section:"Anexo A",topic:"Bases de datos y SQL",difficulty:"media",text:"¿Qué identifica de forma única cada fila de una tabla?",options:["Clave foránea.","Clave primaria.","Trigger."],answer:1,explanation:"La clave primaria identifica registros de forma única.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:72,section:"Anexo A",topic:"Bases de datos y SQL",difficulty:"media",text:"¿Qué mantiene la integridad referencial entre tablas?",options:["Clave foránea.","Índice de pantalla.","Puerto TCP."],answer:0,explanation:"La clave foránea referencia una clave de otra tabla.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:73,section:"Anexo A",topic:"Bases de datos y SQL",difficulty:"media",text:"¿Qué instrucción SQL pertenece a DQL?",options:["SELECT.","DROP.","GRANT."],answer:0,explanation:"SELECT consulta datos; por eso se asocia a DQL.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:74,section:"Anexo A",topic:"Bases de datos y SQL",difficulty:"media",text:"¿Qué sentencia pertenece a DDL?",options:["INSERT.","CREATE TABLE.","COMMIT."],answer:1,explanation:"DDL define estructuras como tablas.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:75,section:"Anexo A",topic:"Bases de datos y SQL",difficulty:"media",text:"¿Qué sentencia pertenece a DML?",options:["UPDATE.","REVOKE.","CREATE INDEX."],answer:0,explanation:"DML manipula datos: INSERT, UPDATE, DELETE.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:76,section:"Anexo A",topic:"Bases de datos y SQL",difficulty:"alta",text:"¿Qué hacen COMMIT y ROLLBACK?",options:["Gestionan transacciones.","Crean usuarios Windows.","Asignan direcciones IP."],answer:0,explanation:"COMMIT confirma y ROLLBACK deshace una transacción.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:77,section:"Anexo A",topic:"Bases de datos y SQL",difficulty:"media",text:"¿Qué tipo de NoSQL es Redis principalmente?",options:["Documental.","Clave-valor.","Relacional puro."],answer:1,explanation:"Redis es una base NoSQL clave-valor en memoria.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:78,section:"Anexo A",topic:"Programación y desarrollo",difficulty:"media",text:"¿Qué es un algoritmo?",options:["Una secuencia finita de pasos para resolver un problema.","Un puerto TCP.","Una unidad de disco."],answer:0,explanation:"Un algoritmo describe pasos ordenados para obtener un resultado.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:79,section:"Anexo A",topic:"Programación y desarrollo",difficulty:"media",text:"¿Qué estructura repite instrucciones mientras se cumple una condición?",options:["Bucle.","Variable constante.","Clave primaria."],answer:0,explanation:"Los bucles repiten instrucciones.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:80,section:"Anexo A",topic:"Programación y desarrollo",difficulty:"media",text:"¿Qué herramienta permite control de versiones distribuido?",options:["Git.","BIOS.","RAID 0."],answer:0,explanation:"Git permite registrar cambios y trabajar con ramas/repositorios.",reference:"Programa AENA IIIJ05 2026 - Anexo A"},
{id:81,section:"Anexo B",topic:"Protección de datos",difficulty:"media",text:"Según la normativa de protección de datos, ¿qué es un dato personal?",options:["Cualquier información sobre una persona física identificada o identificable.","Solo una contraseña cifrada.","Únicamente datos de empresas."],answer:0,explanation:"Dato personal es información relativa a una persona física identificada o identificable.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:82,section:"Anexo B",topic:"Protección de datos",difficulty:"media",text:"¿Quién decide los fines y medios del tratamiento?",options:["Encargado del tratamiento.","Responsable del tratamiento.","Usuario invitado."],answer:1,explanation:"El responsable determina fines y medios.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:83,section:"Anexo B",topic:"Protección de datos",difficulty:"media",text:"¿Quién trata datos por cuenta del responsable?",options:["Encargado del tratamiento.","Interesado exclusivamente.","Router perimetral."],answer:0,explanation:"El encargado trata datos siguiendo instrucciones del responsable.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:84,section:"Anexo B",topic:"Protección de datos",difficulty:"media",text:"¿Qué derecho permite obtener copia de los datos tratados?",options:["Derecho de acceso.","Derecho de VLAN.","Derecho de NAT."],answer:0,explanation:"El derecho de acceso permite conocer y obtener información sobre el tratamiento.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:85,section:"Anexo B",topic:"Protección de datos",difficulty:"media",text:"¿Qué derecho permite solicitar la eliminación de datos cuando proceda?",options:["Rectificación.","Supresión.","Port mirroring."],answer:1,explanation:"El derecho de supresión permite pedir la eliminación en ciertos casos.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:86,section:"Anexo B",topic:"Protección de datos",difficulty:"alta",text:"¿Qué principio exige tratar solo los datos necesarios?",options:["Minimización de datos.","Latencia mínima.","Fragmentación IP."],answer:0,explanation:"La minimización limita los datos a lo adecuado y necesario.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:87,section:"Anexo B",topic:"Protección de datos",difficulty:"media",text:"¿Qué es una brecha de seguridad de datos personales?",options:["Un incidente que afecta a confidencialidad, integridad o disponibilidad de datos.","Una mejora de rendimiento.","Una consulta SELECT."],answer:0,explanation:"Una brecha compromete datos personales accidental o ilícitamente.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:88,section:"Anexo B",topic:"Protección de datos",difficulty:"media",text:"¿Qué derecho digital reconoce la desconexión fuera del tiempo de trabajo?",options:["Desconexión digital.","Portabilidad IP.","Acceso root."],answer:0,explanation:"La desconexión digital protege el descanso y conciliación.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:89,section:"Anexo B",topic:"Igualdad",difficulty:"media",text:"¿Qué es discriminación directa por razón de sexo?",options:["Trato menos favorable por razón de sexo.","Una medida de backup.","Una regla de firewall."],answer:0,explanation:"Hay discriminación directa cuando se trata peor a una persona por su sexo.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:90,section:"Anexo B",topic:"Igualdad",difficulty:"media",text:"¿Qué es discriminación indirecta?",options:["Una norma aparentemente neutra que perjudica especialmente a un sexo.","Un acceso remoto.","Una copia diferencial."],answer:0,explanation:"La discriminación indirecta puede esconderse en criterios aparentemente neutros.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:91,section:"Anexo B",topic:"Igualdad",difficulty:"media",text:"¿Qué finalidad tienen las acciones positivas?",options:["Corregir situaciones de desigualdad real.","Eliminar derechos laborales.","Sustituir auditorías."],answer:0,explanation:"Las acciones positivas buscan compensar desigualdades.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:92,section:"Anexo B",topic:"Igualdad",difficulty:"media",text:"¿Qué instrumento ordena medidas de igualdad en empresas?",options:["Plan de igualdad.","Plan de direccionamiento IP.","Plan de backup incremental."],answer:0,explanation:"El plan de igualdad recoge medidas para evitar discriminación.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:93,section:"Anexo B",topic:"Igualdad",difficulty:"media",text:"¿Qué significa transversalidad del principio de igualdad?",options:["Integrar la igualdad en todas las políticas y actuaciones.","Configurar VLAN troncales.","Cambiar contraseñas."],answer:0,explanation:"La igualdad debe incorporarse de forma general a la actuación pública.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:94,section:"Anexo B",topic:"Igualdad",difficulty:"alta",text:"¿Qué es acoso por razón de sexo?",options:["Conducta basada en el sexo que atenta contra la dignidad y crea entorno ofensivo.","Cualquier incidencia informática.","Un permiso NTFS."],answer:0,explanation:"Es una conducta discriminatoria vinculada al sexo.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:95,section:"Anexo B",topic:"Violencia de género",difficulty:"media",text:"¿Cuál es el objeto de la LO 1/2004?",options:["Actuar contra la violencia ejercida sobre mujeres por quienes sean o hayan sido sus parejas.","Regular únicamente redes locales.","Crear bases NoSQL."],answer:0,explanation:"La ley aborda la violencia de género en el ámbito definido por la norma.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:96,section:"Anexo B",topic:"Violencia de género",difficulty:"media",text:"¿Qué formas puede incluir la violencia de género?",options:["Física y psicológica, incluidas amenazas o coacciones.","Solo fallos de software.","Únicamente delitos económicos."],answer:0,explanation:"Incluye violencia física, psicológica, amenazas, coacciones y privación de libertad.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:97,section:"Anexo B",topic:"Violencia de género",difficulty:"media",text:"¿Qué busca la sensibilización en violencia de género?",options:["Prevenir y concienciar a la sociedad.","Instalar antivirus.","Configurar DHCP."],answer:0,explanation:"La sensibilización contribuye a prevención y rechazo social.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:98,section:"Anexo B",topic:"Violencia de género",difficulty:"media",text:"¿Qué derechos contempla la protección integral de las víctimas?",options:["Asistencia, protección y apoyo integral.","Solo acceso a impresoras.","Solo permisos de red."],answer:0,explanation:"La ley prevé derechos de asistencia, protección y tutela.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:99,section:"Anexo B",topic:"Violencia de género",difficulty:"alta",text:"¿Qué se persigue respecto a la publicidad discriminatoria?",options:["Evitar contenidos que utilicen imagen de la mujer de forma vejatoria o discriminatoria.","Aumentar el tamaño de anuncios.","Crear logs de servidor."],answer:0,explanation:"La normativa busca impedir mensajes discriminatorios o vejatorios.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:100,section:"Anexo B",topic:"Protección de datos",difficulty:"alta",text:"¿Qué significa seudonimización?",options:["Tratar datos de modo que no puedan atribuirse sin información adicional separada.","Eliminar toda seguridad.","Publicar datos en abierto."],answer:0,explanation:"La seudonimización reduce vinculación directa con una persona.",reference:"Programa AENA IIIJ05 2026 - Anexo B"},
{id:101,section:"Supuesto teórico-práctico",topic:"Diagnóstico DHCP",difficulty:"media",text:"Un PC obtiene IP 169.254.12.8 y no navega. ¿Qué comprobarías primero?",options:["Conectividad con servidor DHCP o configuración DHCP.","El puerto SMTP 25.","La firma digital del usuario."],answer:0,explanation:"169.254.x.x indica autoconfiguración APIPA por fallo DHCP.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:102,section:"Supuesto teórico-práctico",topic:"DNS",difficulty:"media",text:"Un usuario hace ping a 8.8.8.8 pero no abre www.aena.es. ¿Qué fallo es más probable?",options:["Resolución DNS.","Tarjeta gráfica.","Permiso NTFS."],answer:0,explanation:"Si llega por IP pero no por nombre, sospecha DNS.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:103,section:"Supuesto teórico-práctico",topic:"Gateway",difficulty:"media",text:"Un equipo comunica con su LAN pero no con Internet. IP y DNS son correctos. ¿Qué revisarías?",options:["Puerta de enlace predeterminada.","Tipo de teclado.","Puerto POP3."],answer:0,explanation:"Sin gateway correcto no sale de la subred.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:104,section:"Supuesto teórico-práctico",topic:"Permisos",difficulty:"alta",text:"Un usuario tiene lectura en recurso compartido y modificación en NTFS. ¿Qué permiso efectivo tendrá por red?",options:["Lectura.","Modificación total.","Control total."],answer:0,explanation:"Entre compartido y NTFS se aplica el más restrictivo.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:105,section:"Supuesto teórico-práctico",topic:"GPO",difficulty:"alta",text:"Una GPO no se aplica a un usuario aunque está creada. ¿Qué revisarías?",options:["Vinculación a OU, filtrado de seguridad y herencia.","La MTU del monitor.","El puerto HDMI."],answer:0,explanation:"Las GPO dependen de vínculo, alcance, filtrado y herencia.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:106,section:"Supuesto teórico-práctico",topic:"VLAN",difficulty:"alta",text:"Un PC en una sala no comunica con su servidor aunque el cable funciona. Otros PCs sí. ¿Qué causa es plausible?",options:["Puerto del switch en VLAN incorrecta.","Resolución de pantalla incorrecta.","Backup completo reciente."],answer:0,explanation:"Una VLAN incorrecta puede aislar el equipo.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:107,section:"Supuesto teórico-práctico",topic:"Firewall",difficulty:"media",text:"RDP está activo pero no conecta desde otra red. ¿Qué revisarías?",options:["Puerto 3389 permitido en firewall y ruta.","Puerto 53 UDP exclusivamente.","La caché L2."],answer:0,explanation:"RDP usa 3389 y puede ser bloqueado por firewall o red.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:108,section:"Supuesto teórico-práctico",topic:"Certificados",difficulty:"media",text:"Una web HTTPS muestra aviso de seguridad por certificado caducado. ¿Qué debe hacerse?",options:["Renovar o sustituir el certificado TLS.","Desactivar DNS permanentemente.","Formatear clientes."],answer:0,explanation:"Un certificado caducado rompe la confianza TLS.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:109,section:"Supuesto teórico-práctico",topic:"Backups",difficulty:"alta",text:"Tras ransomware, los snapshots locales también están cifrados. ¿Qué habría reducido más el impacto?",options:["Copias offline/inmutables probadas.","Más memoria RAM.","Cambiar monitor."],answer:0,explanation:"Las copias inmutables u offline protegen ante cifrado del entorno.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:110,section:"Supuesto teórico-práctico",topic:"RAID",difficulty:"media",text:"Un RAID 1 aparece degradado tras fallo de un disco. ¿Qué acción procede?",options:["Sustituir disco fallido y reconstruir el espejo.","Eliminar ambos discos.","Cambiar DNS."],answer:0,explanation:"RAID 1 tolera fallo de un disco y se reconstruye al reemplazarlo.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:111,section:"Supuesto teórico-práctico",topic:"Correo",difficulty:"media",text:"Un usuario recibe correo pero no puede enviar. ¿Qué revisarías?",options:["Configuración SMTP y puerto de salida.","Puerto IMAP únicamente.","Permisos de carpeta local."],answer:0,explanation:"El envío depende de SMTP.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:112,section:"Supuesto teórico-práctico",topic:"AD/DNS",difficulty:"alta",text:"Un equipo no puede unirse al dominio. Tiene IP correcta pero DNS apunta al router externo. ¿Qué corregirías?",options:["Configurar DNS del cliente hacia el DNS del dominio.","Cambiar a POP3.","Reducir brillo."],answer:0,explanation:"Active Directory depende de DNS interno del dominio.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:113,section:"Supuesto teórico-práctico",topic:"Diagnóstico OSI",difficulty:"alta",text:"No hay enlace físico en una roseta. ¿Qué capa OSI revisarías primero?",options:["Capa física.","Capa aplicación.","Capa sesión."],answer:0,explanation:"Sin enlace físico, se empieza por capa 1.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:114,section:"Supuesto teórico-práctico",topic:"DHCP Relay",difficulty:"alta",text:"Clientes de otra VLAN no reciben IP, pero el servidor DHCP funciona en su VLAN. ¿Qué falta probablemente?",options:["DHCP Relay o IP helper.","Certificado SSL.","Trigger SQL."],answer:0,explanation:"DHCP necesita relay para cruzar redes/VLAN.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:115,section:"Supuesto teórico-práctico",topic:"DNS",difficulty:"media",text:"Un registro DNS interno apunta a una IP antigua. ¿Qué acción es adecuada?",options:["Actualizar el registro y limpiar caché si procede.","Borrar usuarios AD.","Cambiar RAID."],answer:0,explanation:"Los registros DNS deben reflejar la IP correcta.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:116,section:"Supuesto teórico-práctico",topic:"Contenedores",difficulty:"media",text:"Una aplicación se despliega con sus dependencias aisladas compartiendo kernel del host. ¿Qué tecnología encaja?",options:["Contenedor.","Máquina física únicamente.","RAID 10."],answer:0,explanation:"Los contenedores empaquetan app y dependencias compartiendo kernel.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:117,section:"Supuesto teórico-práctico",topic:"Latencia",difficulty:"media",text:"Una aplicación responde lentamente por red aunque no hay pérdida de paquetes. ¿Qué métrica revisarías?",options:["Latencia.","Color del cable.","Clave primaria."],answer:0,explanation:"La latencia mide el retardo de comunicación.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:118,section:"Supuesto teórico-práctico",topic:"Seguridad",difficulty:"alta",text:"Un usuario introduce credenciales en una web falsa recibida por email. ¿Qué incidente es?",options:["Phishing.","RAID degradado.","Normalización."],answer:0,explanation:"Es una suplantación para robar credenciales.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:119,section:"Supuesto teórico-práctico",topic:"Backup restore",difficulty:"alta",text:"Una copia existe pero nunca se ha probado restauración. ¿Cuál es el riesgo?",options:["Que no sea recuperable cuando haga falta.","Que aumente DNS.","Que mejore automáticamente RTO."],answer:0,explanation:"Un backup no verificado puede fallar al restaurar.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:120,section:"Supuesto teórico-práctico",topic:"Cuenta bloqueada",difficulty:"media",text:"Un usuario no puede iniciar sesión y aparece cuenta bloqueada. ¿Qué revisarías?",options:["Intentos fallidos, política de bloqueo y posible contraseña guardada.","MTU del switch.","Conector SATA."],answer:0,explanation:"Los bloqueos suelen venir de intentos fallidos o credenciales antiguas.",reference:"Programa AENA IIIJ05 2026 - Supuesto práctico"},
{id:121,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: server",options:["Servidor.","Cliente.","Cortafuegos."],answer:0,explanation:"Server significa servidor.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:122,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: client",options:["Copia.","Cliente.","Conmutador."],answer:1,explanation:"Client significa cliente.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:123,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: backup",options:["Restauración.","Copia de seguridad.","Amenaza."],answer:1,explanation:"Backup es copia de seguridad.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:124,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: restore",options:["Restaurar.","Desplegar.","Bloquear."],answer:0,explanation:"Restore significa restaurar.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:125,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: vulnerability",options:["Disponibilidad.","Vulnerabilidad.","Latencia."],answer:1,explanation:"Vulnerability es vulnerabilidad.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:126,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: threat",options:["Amenaza.","Parche.","Gateway."],answer:0,explanation:"Threat es amenaza.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:127,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: firewall",options:["Cortafuegos.","Base de datos.","Memoria caché."],answer:0,explanation:"Firewall se traduce como cortafuegos.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:128,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: credentials",options:["Credenciales.","Certificados.","Contenedores."],answer:0,explanation:"Credentials son credenciales.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:129,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: encryption",options:["Cifrado.","Enrutamiento.","Impresión."],answer:0,explanation:"Encryption significa cifrado.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:130,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: certificate",options:["Certificado.","Conector.","Consola."],answer:0,explanation:"Certificate significa certificado.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:131,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"alta",text:"Traduce: packet loss",options:["Pérdida de paquetes.","Bloqueo de cuenta.","Carpeta compartida."],answer:0,explanation:"Packet loss es pérdida de paquetes.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:132,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: latency",options:["Latencia.","Licencia.","Lectura."],answer:0,explanation:"Latency es latencia.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:133,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"alta",text:"Traduce: default gateway",options:["Puerta de enlace predeterminada.","Servidor de correo.","Disco principal."],answer:0,explanation:"Default gateway es puerta de enlace predeterminada.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:134,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"alta",text:"Traduce: network interface card",options:["Tarjeta de interfaz de red.","Copia incremental.","Controlador de dominio."],answer:0,explanation:"NIC es tarjeta de interfaz de red.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:135,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"alta",text:"Traduce: high availability",options:["Alta disponibilidad.","Alta latencia.","Alta fragmentación."],answer:0,explanation:"High availability es alta disponibilidad.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:136,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: rollback",options:["Reversión.","Puente de red.","Amenaza."],answer:0,explanation:"Rollback significa reversión o vuelta atrás.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:137,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"alta",text:"Traduce: root cause",options:["Causa raíz.","Usuario raíz solamente.","Raíz cuadrada."],answer:0,explanation:"Root cause es causa raíz.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:138,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: troubleshooting",options:["Resolución de problemas.","Cifrado asimétrico.","Puerto de enlace."],answer:0,explanation:"Troubleshooting es diagnóstico o resolución de problemas.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:139,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: account locked out",options:["Cuenta bloqueada.","Cuenta eliminada.","Cuenta compartida."],answer:0,explanation:"Account locked out significa cuenta bloqueada.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:140,section:"Inglés técnico",topic:"Traducción técnica",difficulty:"media",text:"Traduce: shared folder",options:["Carpeta compartida.","Archivo oculto.","Servidor caído."],answer:0,explanation:"Shared folder es carpeta compartida.",reference:"Programa AENA IIIJ05 2026 - Inglés técnico"},
{id:141,section:"Inglés escrito general",topic:"Present simple",difficulty:"A2",text:"Choose the correct sentence.",options:["She work in an office.","She works in an office.","She working in an office.","She are work in an office."],answer:1,explanation:"Con he/she/it en present simple se añade -s.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:142,section:"Inglés escrito general",topic:"Present continuous",difficulty:"A2",text:"Complete: I ___ studying now.",options:["am","is","are","be"],answer:0,explanation:"Con I se usa am.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:143,section:"Inglés escrito general",topic:"Prepositions",difficulty:"A2",text:"Complete: The meeting is ___ Monday.",options:["in","on","at","to"],answer:1,explanation:"Los días de la semana usan on.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:144,section:"Inglés escrito general",topic:"Articles",difficulty:"A2",text:"Complete: I need ___ umbrella.",options:["a","an","the one","any"],answer:1,explanation:"Umbrella empieza con sonido vocálico, se usa an.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:145,section:"Inglés escrito general",topic:"Vocabulary",difficulty:"A2",text:"What is the opposite of big?",options:["Small","Long","Fast","Clean"],answer:0,explanation:"Small es lo contrario de big.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:146,section:"Inglés escrito general",topic:"Past simple",difficulty:"A2",text:"Complete: Yesterday, we ___ to the airport.",options:["go","went","gone","going"],answer:1,explanation:"Went es pasado simple de go.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:147,section:"Inglés escrito general",topic:"Questions",difficulty:"A2",text:"Choose the correct question.",options:["Where you live?","Where do you live?","Where does you live?","Where living you?"],answer:1,explanation:"En present simple se usa do para you.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:148,section:"Inglés escrito general",topic:"Quantifiers",difficulty:"A2",text:"Complete: There are ___ apples on the table.",options:["some","any much","a","an"],answer:0,explanation:"Some se usa con plural afirmativo.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:149,section:"Inglés escrito general",topic:"Pronouns",difficulty:"A2",text:"Complete: This is Ana. ___ is my sister.",options:["He","She","It","They"],answer:1,explanation:"She se usa para femenino singular.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:150,section:"Inglés escrito general",topic:"Reading",difficulty:"A2",text:"Text: The shop opens at 9:00 and closes at 18:00. When does it close?",options:["At 9:00","At 12:00","At 18:00","At 8:00"],answer:2,explanation:"El texto dice que cierra a las 18:00.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:151,section:"Inglés escrito general",topic:"Modal verbs",difficulty:"A2",text:"Complete: You ___ wear a seat belt in a car.",options:["must","to must","must to","musts"],answer:0,explanation:"Must va seguido de infinitivo sin to.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:152,section:"Inglés escrito general",topic:"Vocabulary",difficulty:"A2",text:"Which word is related to health?",options:["Doctor","Printer","Keyboard","Invoice"],answer:0,explanation:"Doctor está relacionado con salud.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:153,section:"Inglés escrito general",topic:"Comparatives",difficulty:"A2",text:"Complete: This laptop is ___ than mine.",options:["new","newer","newest","more new"],answer:1,explanation:"Newer es el comparativo de new.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:154,section:"Inglés escrito general",topic:"Future",difficulty:"A2",text:"Complete: Tomorrow I ___ call you.",options:["will","was","did","am been"],answer:0,explanation:"Will se usa para futuro.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:155,section:"Inglés escrito general",topic:"Reading",difficulty:"A2",text:"Message: Please bring your ID card to the appointment. What must you bring?",options:["A laptop","Your ID card","A ticket","A book"],answer:1,explanation:"El mensaje pide llevar el documento de identidad.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:156,section:"Inglés escrito general",topic:"Present perfect",difficulty:"B1",text:"Complete: I ___ finished the report.",options:["have","has","am","did"],answer:0,explanation:"Con I se usa have + participio.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:157,section:"Inglés escrito general",topic:"Conditionals",difficulty:"B1",text:"Complete: If it rains, we ___ stay at home.",options:["will","would","were","had"],answer:0,explanation:"First conditional: if + present, will + infinitive.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:158,section:"Inglés escrito general",topic:"Past continuous",difficulty:"B1",text:"Complete: I was working when you ___.",options:["called","call","calling","have called"],answer:0,explanation:"Past continuous + past simple para acción interrumpida.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:159,section:"Inglés escrito general",topic:"Connectors",difficulty:"B1",text:"Complete: I was tired, ___ I finished the task.",options:["but","because","so that","although of"],answer:0,explanation:"But introduce contraste.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:160,section:"Inglés escrito general",topic:"Email comprehension",difficulty:"B1",text:"Email: Please confirm your attendance before Friday. What should you do?",options:["Cancel the meeting.","Confirm attendance before Friday.","Send an invoice.","Change password."],answer:1,explanation:"El email pide confirmar asistencia antes del viernes.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:161,section:"Inglés escrito general",topic:"Vocabulary",difficulty:"B1",text:"Which word means the same as begin?",options:["Start","Finish","Break","Forget"],answer:0,explanation:"Begin y start son sinónimos.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:162,section:"Inglés escrito general",topic:"Prepositions",difficulty:"B1",text:"Complete: I am interested ___ this position.",options:["on","in","at","for"],answer:1,explanation:"La expresión correcta es interested in.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:163,section:"Inglés escrito general",topic:"Passive voice",difficulty:"B1",text:"Complete: The email ___ sent yesterday.",options:["was","were","is send","did"],answer:0,explanation:"Pasiva en pasado: was/were + participio.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:164,section:"Inglés escrito general",topic:"Relative clauses",difficulty:"B1",text:"Complete: This is the person ___ helped me.",options:["who","which","where","when"],answer:0,explanation:"Who se usa para personas.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:165,section:"Inglés escrito general",topic:"Use of English",difficulty:"B1",text:"Choose the correct sentence.",options:["I have lived here since 2020.","I live here since 2020.","I am live here since 2020.","I living here since 2020."],answer:0,explanation:"Con since y duración hasta ahora se usa present perfect.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:166,section:"Inglés escrito general",topic:"Modal verbs",difficulty:"B1",text:"Complete: You ___ smoke in this area. It is forbidden.",options:["must not","do not must","must to not","not must"],answer:0,explanation:"Must not expresa prohibición.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:167,section:"Inglés escrito general",topic:"Reading",difficulty:"B1",text:"Notice: The main entrance is closed. Please use the side door. What should visitors do?",options:["Use the side door.","Wait outside all day.","Use the main entrance.","Go home."],answer:0,explanation:"El aviso indica usar la puerta lateral.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:168,section:"Inglés escrito general",topic:"Vocabulary",difficulty:"B1",text:"What does delay mean?",options:["A period when something is late.","A payment document.","A fast answer.","A password."],answer:0,explanation:"Delay significa retraso.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:169,section:"Inglés escrito general",topic:"Future forms",difficulty:"B1",text:"Complete: We ___ going to review the document tomorrow.",options:["are","is","am","be"],answer:0,explanation:"Con we se usa are.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:170,section:"Inglés escrito general",topic:"Reported speech",difficulty:"B1",text:"Direct: He said, I am busy. Reported: He said that he ___ busy.",options:["was","is always","were","be"],answer:0,explanation:"En estilo indirecto suele cambiar am a was.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:171,section:"Inglés escrito general",topic:"Conditionals",difficulty:"B2",text:"Complete: If I had more time, I ___ learn another language.",options:["would","will","am","have"],answer:0,explanation:"Second conditional: if + past, would + infinitive.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:172,section:"Inglés escrito general",topic:"Present perfect continuous",difficulty:"B2",text:"Complete: She ___ working here for five years.",options:["has been","have been","is been","was been"],answer:0,explanation:"Has been + -ing expresa duración hasta el presente.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:173,section:"Inglés escrito general",topic:"Passive/modal",difficulty:"B2",text:"Complete: The report ___ be submitted by Friday.",options:["must","must to","has","did"],answer:0,explanation:"Modal + be + participio en pasiva.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:174,section:"Inglés escrito general",topic:"Connectors",difficulty:"B2",text:"Complete: ___ the traffic, we arrived on time.",options:["Despite","Although","Because","However of"],answer:0,explanation:"Despite va seguido de sustantivo o gerundio.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:175,section:"Inglés escrito general",topic:"Reading inference",difficulty:"B2",text:"Text: The update fixed the login issue, but some users still report slow performance. What remains a problem?",options:["Performance is still slow for some users.","Nobody can log in.","The update was cancelled.","The server was removed."],answer:0,explanation:"El texto dice que algunos usuarios siguen notando lentitud.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:176,section:"Inglés escrito general",topic:"Vocabulary",difficulty:"B2",text:"Which word is closest to reliable?",options:["Dependable","Dangerous","Temporary","Noisy"],answer:0,explanation:"Reliable significa fiable.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:177,section:"Inglés escrito general",topic:"Relative clauses",difficulty:"B2",text:"Complete: The system, ___ was installed last week, is working well.",options:["which","who","where","what"],answer:0,explanation:"Which se refiere a cosas.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:178,section:"Inglés escrito general",topic:"Use of English",difficulty:"B2",text:"Choose the correct sentence.",options:["I look forward to hearing from you.","I look forward to hear from you.","I look forward hearing you.","I look forward for hear from you."],answer:0,explanation:"Look forward to + gerundio.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:179,section:"Inglés escrito general",topic:"Quantifiers",difficulty:"B2",text:"Complete: There is ___ evidence to support the claim.",options:["enough","many","few","several"],answer:0,explanation:"Evidence es incontable; enough encaja.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:180,section:"Inglés escrito general",topic:"Comparatives",difficulty:"B2",text:"Complete: This is ___ solution we have found.",options:["the most efficient","more efficient","efficienter","the efficientest"],answer:0,explanation:"Superlativo con adjetivo largo: the most efficient.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:181,section:"Inglés escrito general",topic:"Email comprehension",difficulty:"B2",text:"Email: Could you please let me know whether the invoice has already been processed? What is being asked?",options:["Whether the invoice has been processed.","Whether the flight is delayed.","Whether the password changed.","Whether the room is clean."],answer:0,explanation:"Pregunta si la factura ya fue procesada.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:182,section:"Inglés escrito general",topic:"Grammar",difficulty:"B2",text:"Complete: I wish I ___ more free time.",options:["had","have","will have","am having"],answer:0,explanation:"Wish + past simple expresa deseo presente.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:183,section:"Inglés escrito general",topic:"Vocabulary",difficulty:"B2",text:"What is the opposite of temporary?",options:["Permanent","Partial","Previous","Possible"],answer:0,explanation:"Permanent es lo contrario de temporary.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:184,section:"Inglés escrito general",topic:"Connectors",difficulty:"B2",text:"Complete: I saved the file ___ the computer crashed.",options:["before","during of","despite that","because of to"],answer:0,explanation:"Before indica anterioridad temporal.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:185,section:"Inglés escrito general",topic:"Quantifiers",difficulty:"B2",text:"Complete: There is ___ information available about the incident.",options:["little","few","many","several"],answer:0,explanation:"Information es incontable; little indica poca cantidad.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:186,section:"Inglés escrito general",topic:"Advanced grammar",difficulty:"C1",text:"Choose the most natural sentence.",options:["Had I known about the delay, I would have called you.","If I would have known, I had called you.","Had I knew, I call you.","I had know, I would call you."],answer:0,explanation:"Es inversión en tercer condicional.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:187,section:"Inglés escrito general",topic:"Advanced connectors",difficulty:"C1",text:"Complete: The proposal is technically sound; ___, it lacks a realistic budget.",options:["nonetheless","because","in order to","so that of"],answer:0,explanation:"Nonetheless introduce contraste.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:188,section:"Inglés escrito general",topic:"Reading inference",difficulty:"C1",text:"Text: The rollout was delayed, not because the code failed, but because approval took longer than expected. What caused the delay?",options:["The approval process.","A coding error.","A hardware failure.","A lack of users."],answer:0,explanation:"La causa fue el proceso de aprobación.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:189,section:"Inglés escrito general",topic:"Advanced vocabulary",difficulty:"C1",text:"Which word is closest to concise?",options:["Brief and clear","Long and repetitive","Angry and informal","Hidden and illegal"],answer:0,explanation:"Concise significa breve y claro.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:190,section:"Inglés escrito general",topic:"Advanced grammar",difficulty:"C1",text:"Complete: Rarely ___ such a clear explanation.",options:["have I seen","I have seen","I saw have","have seen I"],answer:0,explanation:"Con adverbios negativos iniciales puede haber inversión.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:191,section:"Inglés escrito general",topic:"Register",difficulty:"C1",text:"Which sentence is most appropriate for a professional apology?",options:["We apologise for the inconvenience and are working to resolve the issue.","Oops, our bad.","You people broke it.","Forget it."],answer:0,explanation:"Es formal, profesional y responsable.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:192,section:"Inglés escrito general",topic:"Advanced conditionals",difficulty:"C1",text:"Complete: Provided that the data is accurate, the report ___ reliable.",options:["should be","must to be","would to be","had been always"],answer:0,explanation:"Provided that expresa condición; should be encaja.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:193,section:"Inglés escrito general",topic:"Reading nuance",difficulty:"C1",text:"Text: The deadline is flexible, but only within reasonable limits. What does it imply?",options:["Some delay may be accepted, but not unlimited delay.","There is no deadline.","The task is cancelled.","Only unreasonable delays are allowed."],answer:0,explanation:"Flexible con límites no significa libertad total.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:194,section:"Inglés escrito general",topic:"Collocations",difficulty:"C1",text:"Complete: The manager raised ___ about the security procedure.",options:["concerns","concernings","concerned","concerningness"],answer:0,explanation:"La colocación correcta es raise concerns.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:195,section:"Inglés escrito general",topic:"Advanced passive",difficulty:"C1",text:"Complete: The system is believed ___ compromised before the patch.",options:["to have been","to has been","having been to","to be have"],answer:0,explanation:"Estructura: is believed to have been.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:196,section:"Inglés escrito general",topic:"C2 nuance",difficulty:"C2",text:"Choose the option that best preserves the meaning: The change is far from trivial.",options:["The change is quite significant.","The change is very simple.","The change is unrelated.","The change is cancelled."],answer:0,explanation:"Far from trivial significa importante o no simple.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:197,section:"Inglés escrito general",topic:"C2 vocabulary",difficulty:"C2",text:"Complete: The explanation was clear, but it lacked ___ evidence.",options:["substantive","blue","sleeping","edible"],answer:0,explanation:"Substantive evidence significa evidencia sólida.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:198,section:"Inglés escrito general",topic:"C2 idiom",difficulty:"C2",text:"What does to get to the bottom of an issue mean?",options:["To discover the real cause of it.","To delete it unread.","To move it down physically.","To make it expensive."],answer:0,explanation:"La expresión significa investigar hasta hallar la causa real.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:199,section:"Inglés escrito general",topic:"C2 grammar",difficulty:"C2",text:"Choose the most accurate sentence.",options:["No sooner had the update been deployed than users reported errors.","No sooner the update had deployed that users reported errors.","No sooner was deploy the update than errors users report.","No sooner had deploy the update when users reported errors."],answer:0,explanation:"No sooner + inversión + than.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"},
{id:200,section:"Inglés escrito general",topic:"C2 inference",difficulty:"C2",text:"Text: While the figures appear encouraging, they should be interpreted with caution due to the limited sample size. What is the writer's position?",options:["The results look positive, but they are not fully conclusive.","The results are completely false.","The sample size proves everything.","The figures are irrelevant."],answer:0,explanation:"El autor es moderadamente optimista, pero prudente.",reference:"Programa AENA IIIJ05 2026 - Inglés escrito general"}
